import React, { Component } from "react";
import Menu from "@material-ui/core/Menu";
import MenuItem from "@material-ui/core/MenuItem";
import Snackbar from "@material-ui/core/Snackbar";
import IconButton from "@material-ui/core/IconButton";
import CloseIcon from "@material-ui/icons/Close";


export default class PlaylistItem extends Component {
  constructor(props) {
    super(props);
    this.state = {
      anchorEl: null,
      snackbarText:""
    };
  }
  componentDidMount() {}

  menuOpen(event) {
    //setAnchorEl(event.currentTarget);
    this.setState({ anchorEl: event.currentTarget });
  }
  menuClose() {
    this.setState({ anchorEl: null });
  }
  removePlaylist(){
    this.setState({snackbarText:"プレイリストから削除しました"});
    this.openSnackBar();
    this.setState({ anchorEl: null });
    this.props.removePlaylist();
  }
  openSnackBar() {
    this.setState({ open: true });
  }
  closeSnackBar(event, reason) {
    if (reason === "clickaway") {
      return;
    }
    this.setState({ open: false });
  }

  render() {
    return (
      <div className="playlist__item">
        <div
          className="playlist__title"
          onClick={() => this.props.setPlayingInfo(this.props.playingInfo)}
        >
          <figure>
            <img
              src={this.props.playingInfo.url}
              alt={this.props.playingInfo.title}
            ></img>
          </figure>
          <div className="playlist__text typo_body2">
            {this.props.playingInfo.title}
          </div>
        </div>

        <div className="playlist__more">
          <button
            className="more-button"
            aria-controls="simple-menu"
            aria-haspopup="true"
            onClick={this.menuOpen.bind(this)}
          ></button>
        </div>

        <Menu
          id="simple-menu"
          anchorEl={this.state.anchorEl}
          keepMounted
          open={Boolean(this.state.anchorEl)}
          onClose={this.menuClose.bind(this)}
        >
          <MenuItem onClick={this.removePlaylist.bind(this)}>
            プレイリストから削除
          </MenuItem>
        </Menu>

        <Snackbar
            anchorOrigin={{
              vertical: "top",
              horizontal: "left"
            }}
            open={this.state.open}
            autoHideDuration={3000}
            onClose={this.closeSnackBar.bind(this)}
            message={this.state.snackbarText}
            action={
              <React.Fragment>
                <IconButton
                  size="small"
                  aria-label="close"
                  color="inherit"
                  onClick={this.closeSnackBar.bind(this)}
                >
                  <CloseIcon fontSize="small" />
                </IconButton>
              </React.Fragment>
            }
          />


      </div>
    );
  }
}
