import React, { Component } from "react";
import "./App.scss";
import { Tab, Tabs, TabList, TabPanel } from "react-tabs";

import Search from "./components/search";
import Dismissible from "./components/dismissible";
import DismissibleItem from "./components/dismissibleItem";
import Playlist from "./components/playlist";
import MoviePlayer from "./components/moviePlayer";

import iconHome from "./images/icon_mdi_home.svg";
import iconAddPlaylist from "./images/icon_mdi_playlist_add.svg";
import iconBack from "./images/icon_back.svg";



export default class App extends Component {
  constructor(props) {
    super(props);
    this.state = {
      playingIndex: "", //再生選択中の動画Index
      playlistInfo: [], //プレイリストのID,title,サムネイルURLがはいった配列
      tabIndex: 0, //選択中タブ
      dismissibleIndex1: 0, //選択中スライドパネル
      dismissibleIndex2: 0, //選択中スライドパネル
      searchedPlayingInfo: "", // サーチで探して再生する動画情報
      playingInfo: [] //プレイリストから再生中の動画情報
    };
  }
  render() {
    return (
      <div className="l-wrap">
        <Tabs
          selectedIndex={this.state.tabIndex}
          onSelect={tabIndex => this.setState({ tabIndex })}
        >
          <TabList>
            <Tab>
              <div
                className="bottomnav-icon"
                onClick={() => this.setState({ dismissibleIndex1: 0 })}
              >
                <div className="bottomnav-icon__img">
                  <img src={iconHome} alt="ホーム" />
                </div>
                <div className="bottomnav-icon__text color_white100">
                  ホーム
                </div>
              </div>
            </Tab>
            <Tab>
              <div
                className="bottomnav-icon"
                onClick={() => this.setState({ dismissibleIndex2: 0 })}
              >
                <div className="bottomnav-icon__img">
                  <img src={iconAddPlaylist} alt="曲を追加" />
                </div>
                <div className="bottomnav-icon__text color_white100">
                  曲を追加
                </div>
              </div>
            </Tab>
          </TabList>

          {/*////////// タブ1 /////////*/}
          <TabPanel>
            <Dismissible
              selectedIndex={this.state.dismissibleIndex1}
              cngIndex={index => this.setState({ dismissibleIndex1: index })}
            >
              <DismissibleItem>
                <div className="l-contwrap">
                  <div className="l-scroll">
                    <section>
                      <div className="searchbox">
                        <div className="input-text">
                          <input
                            type="text"
                            placeholder="Youtube動画URL"
                            onFocus={() => this.setState({ tabIndex: 1 })}
                          />
                        </div>
                      </div>
                    </section>
                    <section>
                      <h3 className="color_white100 typo_headline5">
                        Playlist
                      </h3>
                      <div className="l-unit">
                        <Playlist
                          playlistInfo={this.state.playlistInfo}
                          setStatePlaylist={playlistInfo =>
                            this.setStatePlaylist(playlistInfo)
                          }
                          setPlayingInfo={playingInfo =>
                            this.setPlayingInfo(playingInfo)
                          }
                          removePlaylist={index => this.removePlaylist(index)}
                        />
                      </div>
                    </section>
                  </div>
                </div>
              </DismissibleItem>
              <DismissibleItem>
                <div className="l-contwrap fixtop">
                  <div className="l-unit">
                    <button className="icon-button"
                      onClick={() => this.setState({ dismissibleIndex1: 0 })}
                    >
                      <img src={iconBack} alt="back" />
                    </button>
                    <section>
                      <MoviePlayer
                        playingInfo={this.state.playingInfo}
                        playlistInfo={this.state.playlistInfo}
                        removePlaylist={index => this.removePlaylist(index)}
                      />
                    </section>
                  </div>
                </div>
              </DismissibleItem>
            </Dismissible>
          </TabPanel>

          {/*////////// タブ2 /////////*/}
          <TabPanel>
              <Dismissible
                selectedIndex={this.state.dismissibleIndex2}
                cngIndex={index => this.setState({ dismissibleIndex2: index })}
              >
                <DismissibleItem>
                  <section>
                  <div className="l-contwrap">
                    <Search
                      cngDismissible={index =>
                        this.setState({ dismissibleIndex2: index })
                      }
                      setSearchedPlayingInfo={playingInfo =>
                        this.setState({ searchedPlayingInfo: playingInfo })
                      }
                    />
                  </div>
                  </section>
                </DismissibleItem>
                <DismissibleItem>
                  <div className="l-contwrap fixtop">
                    <div className="l-unit">
                      <button
                        className="icon-button"
                        onClick={() => this.setState({ dismissibleIndex2: 0 })}
                      >
                        <img src={iconBack} alt="back" />
                      </button>
                      <section>
                        <MoviePlayer
                          playingInfo={this.state.searchedPlayingInfo}
                          playlistInfo={this.state.playlistInfo}
                          removePlaylist={index => this.removePlaylist(index)}
                          addPlaylist={movieId => this.addPlaylist(movieId)}
                        />
                      </section>
                    </div>
                  </div>
                </DismissibleItem>
              </Dismissible>
          </TabPanel>
        </Tabs>
      </div>
    );
  }
  /*
   * タブ切り替え
   */
  cngTab(num) {
    this.setState({ tabIndex: num });
  }
  /**
   * 読み込んだプレイリスト情報をStateにセット
   */
  setStatePlaylist(playlistData) {
    //this.setState({ playlist:playlist});
    this.setState({ playlistInfo: playlistData });
  }
  /**
   * 再生中情報をセット　再生
   */
  setPlayingInfo(playingInfo) {
    this.setState({ playingInfo: playingInfo });
    this.setState({ dismissibleIndex1: 1 });
  }
  /**
   * プレイリストに追加
   */
  addPlaylist(movieId) {
    if (this.state.searchedPlayingInfo) {
      let newPlaylistInfo = this.state.playlistInfo;
      newPlaylistInfo.push(this.state.searchedPlayingInfo);
      this.setState({ playlistInfo: newPlaylistInfo });
      this.setCookie();
    }
  }
  /**
   * プレイリストから削除
   */
  removePlaylist(index) {
    let newPlaylistInfo = this.state.playlistInfo;
    newPlaylistInfo.splice(index, 1);
    this.setState({ playlistInfo: newPlaylistInfo });
    this.setCookie();
  }
  /**
   * cookie書き込み
   */
  setCookie() {
    let playlist = [];
    const playlistInfo = this.state.playlistInfo;
    for (var i = 0; i < playlistInfo.length; i++) {
      playlist.push(playlistInfo[i].id);
    }
    document.cookie = "movie_id=" + encodeURIComponent(playlist.join(",")) + ";expires=" + new Date('2025/1/1').toUTCString();
    
  }
}
