import React, { Component } from "react";
import YouTube from "react-youtube";
import Menu from "@material-ui/core/Menu";
import MenuItem from "@material-ui/core/MenuItem";
import Snackbar from "@material-ui/core/Snackbar";
import IconButton from "@material-ui/core/IconButton";
import CloseIcon from "@material-ui/icons/Close";
import iconAdd from "../images/icon_add.svg";

import "./movieplayer.scss";

export default class MoviePlayer extends Component {
  constructor(props) {
    super(props);
    this.state = {
      player: "",
      open: null,
      anchorEl: null,
      snackbarText:""
    };
  }
  componentDidMount(){}
  render() {
    const opts = {
      height: "390",
      width: "640",
      playerVars: {
        // https://developers.google.com/youtube/player_parameters
        autoplay: 0,
        controls: 1,
        showinfo: 0,
        modestbranding: 0,
        rel: 0,
        loop: 1,
        //modestbranding: 0
      }
    };
    let more;
    let menuItem;
    //let snackbarText;
    const playlingInfo = this.props.playingInfo;
    const playlistInfo = this.props.playlistInfo;

    let playingIndex = -1;
    if (playlingInfo.id) {
      for (var i = 0; i < playlistInfo.length; i++) {
        if (playlingInfo.id === playlistInfo[i].id) {
          playingIndex = i;
          break;
        }
      }
    }
    /// プレイリストに入っていない場合
    if (playingIndex === -1) {
      //console.log("プレイリストにはいっていない");
      more = (
        <button
          className="icon-button"
          aria-controls="simple-menu"
          aria-haspopup="true"
          onClick={this.menuOpen.bind(this)}
        ><img src={iconAdd} alt="プレイリストに追加" /></button>
      );
      menuItem = (
        <div onClick={() => this.addPlaylist(playlingInfo.id)}>
          プレイリストに追加
        </div>
      );
      //snackbarText = ("プレイリストに追加しました");
    }
    /// プレイリストに入っている場合
    else {
      //console.log("プレイリストにはいっている");
      more = (
        <button
          className="more-button"
          aria-controls="simple-menu"
          aria-haspopup="true"
          onClick={this.menuOpen.bind(this)}
        ></button>
      );
      menuItem = (
        <div onClick={() => this.removePlaylist()}>プレイリストから削除</div>
      );
      //snackbarText = "プレイリストから削除しました";
    }
    if (playlingInfo) {
      return (
        <div className="movie-player">
          <div>
            <div className="l-unit">
              <div id="youtubeplayer">
                <YouTube
                  videoId={playlingInfo.id}
                  opts={opts}
                  onReady={this._onReady.bind(this)}
                  onEnd={this._onEnd.bind(this)}
                />
              </div>
            </div>
            <div className="l-unit">
              <div className="player-title">
                <h5 className="">
                  <span>{playlingInfo.title}</span>
                </h5>
                <div className="player-title__more">{more}</div>
              </div>
            </div>
          </div>

          <div className="l-unit">
            <select
              name="speed"
              id="speed"
              defaultValue={"1"}
              onChange={this.speedSelect_onChange.bind(this)}
            >
              <option value="0.5">50%</option>
              <option value="0.55">55%</option>
              <option value="0.6">60%</option>
              <option value="0.65">65%</option>
              <option value="0.7">70%</option>
              <option value="0.75">75%</option>
              <option value="0.8">80%</option>
              <option value="0.85">85%</option>
              <option value="0.9">90%</option>
              <option value="0.95">95%</option>
              <option value="1">100%</option>
            </select>
          </div>

          <Menu
            id="simple-menu"
            anchorEl={this.state.anchorEl}
            keepMounted
            open={Boolean(this.state.anchorEl)}
            onClose={this.menuClose.bind(this)}
          >
            <MenuItem onClick={this.menuClose.bind(this)}>{menuItem}</MenuItem>
          </Menu>

          <Snackbar
            anchorOrigin={{
              vertical: "top",
              horizontal: "left"
            }}
            open={this.state.open}
            autoHideDuration={3000}
            onClose={this.closeSnackBar.bind(this)}
            message={this.state.snackbarText}
            action={
              <React.Fragment>
                <IconButton
                  size="small"
                  aria-label="close"
                  color="inherit"
                  onClick={this.closeSnackBar.bind(this)}
                >
                  <CloseIcon fontSize="small" />
                </IconButton>
              </React.Fragment>
            }
          />
        </div>
      );
    } else {
      return <div>error</div>;
    }
  }
  _onReady(event) {
    this.setState({ player: event.target });
    event.target.pauseVideo();
  }
  _onEnd(event) {
    event.target.seekTo(0);
    event.target.pauseVideo();
  }
  speedSelect_onChange(event) {
    if (this.state.player) {
      this.state.player.setPlaybackRate(Number(event.target.value));
    }
  }
  componentDidUpdate() {
    if (this.state.player) {
      this.state.player.stopVideo();
    }
  }

  addPlaylist(movieId) {
    this.setState({snackbarText:"プレイリストに追加しました"});
    this.openSnackBar();
    this.props.addPlaylist(movieId);
  }
  removePlaylist() {
    this.setState({snackbarText:"プレイリストから削除しました"});
    this.openSnackBar();
    this.props.removePlaylist();
  }

  menuOpen(event) {
    this.setState({ anchorEl: event.currentTarget });
  }
  menuClose() {
    this.setState({ anchorEl: null });
  }

  openSnackBar() {
    this.setState({ open: true });
  }
  closeSnackBar(event, reason) {
    if (reason === "clickaway") {
      return;
    }
    this.setState({ open: false });
  }
}
