import React, { Component } from "react";

export default class SearchSuggest extends Component {
  constructor(props) {
    super(props);
    this.state = {
    };
  }
  render() {
    if (this.props.flag === true) {
      if (this.props.id) {
        return (
          <div className="searchbox-suggest">
            <div className="searchbox-suggest__result" onClick={this.props.viewPlayer}>
              <div className="searchbox-suggest__thumbnail">
                <img src={this.props.url} alt={this.props.title} />
              </div>
              <div className="searchbox-suggest__title typo_body2">{this.props.title}</div>
            </div>
          </div>
        );
      } else {
        return (
          <div className="searchbox-suggest">
            <div className="searchbox-suggest__notresult typo_body2">
              動画がみつかりません。
            </div>
          </div>
        );
      }
    } else {
      return <div></div>;
    }
  }
}
