import React, { Component } from "react";
import SearchSuggest from "./searchSuggest";
import "./search.scss";

export default class Search extends Component {
  constructor(props) {
    super(props);
    this.state = {
      flag: false,
      id: "",
      title: "",
      url: "",
      searchInput : React.createRef(),
      seachInputCloase : React.createRef()
    };
  }
  componentDidMount() {
    document.getElementById("seachbox").focus();
  }
  render() {
    return (
      <div className="searchbox">
        <div className="input-text">
          <input
            id="seachbox"
            type="text"
            placeholder="Youtube動画URL"
            onChange={this.validation.bind(this)}
            onFocus={() => (this.value = "")}
            ref={this.state.searchInput}
          />
          <button className={"input-text__close"} onClick={this.clearInput.bind(this)} ref={this.state.seachInputCloase}>x</button>
        </div>
        <SearchSuggest
          flag={this.state.flag}
          id={this.state.id}
          title={this.state.title}
          url={this.state.url}
          viewPlayer={this.viewPlayer.bind(this)}
        />
      </div>
    );
  }
  // サジェストクリックでプレイヤーを表示
  viewPlayer() {
    //プレイヤー表示
    this.props.setSearchedPlayingInfo({
      id: this.state.id,
      title: this.state.title,
      url: this.state.url
    });
    this.props.cngDismissible(1);
  }
  // youtubeIdチェック
  validation(event) {
    const youtubeUrl = event.target.value;
    //クローズボタン
    if(youtubeUrl.length>0){
      this.state.seachInputCloase.current.classList.add("view");
    }
    const domain = youtubeUrl.slice(0, 17);
    this.resetStateSuggest();

    if (domain === "https://youtu.be/") {
      const movieID = youtubeUrl.split("https://youtu.be/")[1];
      if (movieID.length === 11) {
        this.getMovieInfo(movieID);
      }
    } else if (domain === "https://www.youtu") {
      if (youtubeUrl.split("?")[1]) {
        var prm = youtubeUrl.split("?")[1].split("&");
        for (var i = 0; i < prm.length; i++) {
          if (
            prm[i].split("=")[1] &&
            prm[i].split("=")[0] === "v" &&
            prm[i].split("=")[1].length === 11
          ) {
            this.getMovieInfo(prm[i].split("=")[1]);
            break;
          }
        }
      }
    }
  }
  // 動画情報を取得
  getMovieInfo(movieId) {
    const _this = this;
    const APIKey = "AIzaSyBzXhubOQ-cr_VKGXYGlBqGCek8eppa9dQ";
    fetch(
      "https://www.googleapis.com/youtube/v3/videos?id=" +
        movieId +
        "&key=" +
        APIKey +
        "&part=snippet"
    )
      .then(function(response) {
        console.log("status=" + response.status); //例 200
        console.log(response);
        return response.json();
      })
      .then(function(data) {
        _this.setStateSuggest(data.items);
      })
      .catch(function(err1) {});
  }
  setStateSuggest(items) {
    if (items.length >= 1) {
      this.setState({ id: items[0].id });
      this.setState({ title: items[0].snippet.title });
      this.setState({ url: items[0].snippet.thumbnails.high.url });
      this.setState({ flag: true });
    }
  }
  //サジェスト情報をリセット
  resetStateSuggest() {
    this.setState({ id: "" });
    this.setState({ title: "" });
    this.setState({ url: "" });
    this.setState({ flag: false });
  }
  clearInput(){
    //this.state.searchInput.current.value="";
    this.setState({searchInput:""});
    this.state.seachInputCloase.current.classList.remove("view");
    this.resetStateSuggest()
  }
}
