import React, { Component } from "react";
import PlaylistItem from "./playlist-item";
import "./playlist.scss";

export default class Playlist extends Component {
  constructor(props) {
    super(props);
    this.state = {
    };
  }
  render() {
    let playlist = this.props.playlistInfo.map((info, index) => (
      <PlaylistItem
        key={index}
        index={index}
        playingInfo={info}
        setPlayingInfo={playingInfo => this.setPlayingInfo(playingInfo)}
        removePlaylist={()=>this.props.removePlaylist(index)}
      />
    ));

    if (this.props.playlistInfo.length > 0) {
      return <div className="playlist">{playlist}</div>;
    } else {
      return (
        <div className="playlist">
          <div className="playlist__item">
            <div className="playlist__title">プレイリストはありません</div>
          </div>
        </div>
      );
    }
  }
  componentDidMount() {
    //アプリ起動時のみクッキー取得
    if (this.props.playlistInfo.length === 0 && document.cookie) {
      this.getCookie();
    }else{
      //document.cookie = "movie_id=" + encodeURIComponent("vWYOKFi8pd8") + ";expires=" + new Date('2025/1/1').toUTCString();
      //this.getCookie();
    }
  }
  /**
   * cookie を取得
   */
  getCookie() {
    let cookieData = document.cookie.split(";");
    //id:movie_idのcookie取り出し
    for (var i=0; i<cookieData.length; i++){
      if(cookieData[i].split("=")[0]==="movie_id"){
        let playlistArray=decodeURIComponent(cookieData[i].split("=")[1]).split(",");
        this.getMovieInfo(playlistArray);
      }
    }
  }
  /**
   * cookie を保存
   */
  setCookie() {
  }
  /**
   *  youtubeAPIで動画情報を取得
   */
  getMovieInfo(playlistArray) {
    const APIKey = "AIzaSyBzXhubOQ-cr_VKGXYGlBqGCek8eppa9dQ";
    var _this = this;
    fetch(
      "https://www.googleapis.com/youtube/v3/videos?id=" +
        playlistArray +
        "&key=" +
        APIKey +
        "&part=snippet"
    )
      .then(function(response) {
        console.log("status=" + response.status); //例 200
        return response.json();
      })
      .then(function(data) {
        _this.setStatePlaylist(data.items);
      })
      .catch(function(err1) {
        console.log("err=" + err1);
      });
  }
  /*
   * 読み込んだjsonプレイリストを親コンポーネントのstateにセット
   */
  setStatePlaylist(items) {
    var playlistData = [];
    for (let i = 0; i < items.length; i++) {
      playlistData.push({
        id: items[i].id,
        title: items[i].snippet.title,
        url: items[i].snippet.thumbnails.high.url
      });
    }
    this.props.setStatePlaylist(playlistData);
  }

  /*
   * 再生中を変更
   */
  setPlayingInfo(playingInfo) {
    this.props.setPlayingInfo(playingInfo);
  }
}
